import{_ as e,a as o,b as i,c as t,d as r,e as s}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as d,o as n,c as p,a2 as l}from"./chunks/framework.DnrXFDHb.js";const P=JSON.parse('{"title":"Geolocalização por IP e gerenciamento de usuários","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/Other/ip-geolocation-and-user-management.md","filePath":"pt-BR/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),c={name:"pt-BR/Other/ip-geolocation-and-user-management.md"};function u(m,a,g,h,v,b){return n(),p("div",null,[...a[0]||(a[0]=[l('<h1 id="geolocalizacao-por-ip-e-gerenciamento-de-usuarios" tabindex="-1">Geolocalização por IP e gerenciamento de usuários <a class="header-anchor" href="#geolocalizacao-por-ip-e-gerenciamento-de-usuarios" aria-label="Permalink to &quot;Geolocalização por IP e gerenciamento de usuários&quot;">​</a></h1><p>A geolocalização por IP transforma IPs de uploads, dispositivos de login e outros logs em localizações aproximadas.</p><p>Com ela configurada, o painel mostra melhor a origem de uploads e acessos. O gerenciamento de usuários também permite bloquear ou restaurar permissão de upload para IPs suspeitos.</p><h2 id="onde-configurar" tabindex="-1">Onde configurar <a class="header-anchor" href="#onde-configurar" aria-label="Permalink to &quot;Onde configurar&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Configurações do sistema -&gt; Outras configurações -&gt; Geolocalização por IP</span></span></code></pre></div><p><img src="'+e+`" alt="Geolocalização por IP" loading="lazy"></p><h2 id="configuracoes-disponiveis" tabindex="-1">Configurações disponíveis <a class="header-anchor" href="#configuracoes-disponiveis" aria-label="Permalink to &quot;Configurações disponíveis&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Configuração</th><th>Descrição</th></tr></thead><tbody><tr><td>Idioma da localização</td><td>Define o idioma das localizações exibidas</td></tr><tr><td>MaxMind Account ID</td><td>ID da conta para MaxMind GeoLite Web Service</td></tr><tr><td>MaxMind License Key</td><td>Chave de licença da MaxMind</td></tr><tr><td>Tencent Map Key</td><td>Útil para endereços da China continental</td></tr><tr><td>ipapi Key</td><td>Chave da APILayer ipapi com suporte multilíngue</td></tr></tbody></table><p>Preencha apenas os serviços que você precisa. Sem chaves, o ImgBed tenta fontes gratuitas integradas, mas elas podem ser menos estáveis ou precisas.</p><h2 id="recomendacao-para-portugues" tabindex="-1">Recomendação para português <a class="header-anchor" href="#recomendacao-para-portugues" aria-label="Permalink to &quot;Recomendação para português&quot;">​</a></h2><p>Para mostrar localizações em português ou em vários idiomas, configure MaxMind e, se precisar de resultados multilíngues melhores, adicione ipapi.</p><h2 id="configurar-maxmind" tabindex="-1">Configurar MaxMind <a class="header-anchor" href="#configurar-maxmind" aria-label="Permalink to &quot;Configurar MaxMind&quot;">​</a></h2><p>A MaxMind precisa de:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>Encontre o Account ID no painel da MaxMind, crie uma License Key e cole os dois valores no ImgBed.</p><p><img src="`+o+'" alt="Configuração MaxMind" loading="lazy"></p><h2 id="configurar-ipapi" tabindex="-1">Configurar ipapi <a class="header-anchor" href="#configurar-ipapi" aria-label="Permalink to &quot;Configurar ipapi&quot;">​</a></h2><p>Copie a API Key no console do ipapi.</p><p><img src="'+i+'" alt="Configuração ipapi" loading="lazy"></p><p>Cole em <code>ipapi Key</code> no ImgBed e salve.</p><h2 id="gerenciamento-de-usuarios" tabindex="-1">Gerenciamento de usuários <a class="header-anchor" href="#gerenciamento-de-usuarios" aria-label="Permalink to &quot;Gerenciamento de usuários&quot;">​</a></h2><p>O gerenciamento de usuários abre na parte superior do painel administrativo.</p><p><img src="'+t+'" alt="Gerenciamento de usuários" loading="lazy"></p><p>Ele mostra atividade agrupada por IP.</p><table tabindex="0"><thead><tr><th>Campo</th><th>Descrição</th></tr></thead><tbody><tr><td>IP</td><td>IP de origem</td></tr><tr><td>Localização</td><td>Local aproximado resolvido pelo IP</td></tr><tr><td>Tamanho total enviado</td><td>Soma dos arquivos enviados por esse IP</td></tr><tr><td>Número de uploads</td><td>Quantidade de envios</td></tr><tr><td>Upload permitido</td><td>Desative para bloquear novos uploads desse IP</td></tr></tbody></table><p>Abra a seta à esquerda para ver os arquivos enviados por esse IP. Você verá nome, prévia, tamanho, resultado de moderação, status e horário do upload.</p><p><img src="'+r+'" alt="Filtros avançados" loading="lazy"></p><h2 id="dicas-de-operacao" tabindex="-1">Dicas de operação <a class="header-anchor" href="#dicas-de-operacao" aria-label="Permalink to &quot;Dicas de operação&quot;">​</a></h2><ul><li>Antes de bloquear um IP, confira os arquivos enviados.</li><li>Use busca e ordenação para encontrar IPs recentes, muito ativos ou com consumo alto.</li><li>Localização por IP é estimativa. Use como sinal de apoio, não como prova absoluta.</li></ul><p><img src="'+s+'" alt="Visualização móvel" loading="lazy"></p>',30)])])}const _=d(c,[["render",u]]);export{P as __pageData,_ as default};
